/*!
 * FormFlow v1.0 - Webflow Multistep Forms
 * https://github.com/monsur2003/formflow-scripts
 */
(function(){
  'use strict';

  function init() {
    // Find all forms with data-flowform or auto-detect
    var forms = document.querySelectorAll('[data-flowform], form');
    forms.forEach(function(form) {
      var steps = form.querySelectorAll('[data-step]');
      if (steps.length < 2) return;
      setupForm(form, steps);
    });
  }

  function setupForm(form, steps) {
    var current = 0;
    var total = steps.length;

    // Hide all steps except first
    steps.forEach(function(step, i) {
      step.style.display = i === 0 ? '' : 'none';
    });

    // Update progress + counter
    function updateUI() {
      var pct = ((current + 1) / total) * 100;
      // Progress bar
      var bars = document.querySelectorAll('[data-ff-progress]');
      bars.forEach(function(b) { b.style.width = pct + '%'; });
      // Step counter
      var counts = document.querySelectorAll('[data-ff-count]');
      counts.forEach(function(c) { c.textContent = (current + 1) + ' / ' + total; });
      // Step title
      var titles = document.querySelectorAll('[data-ff-title]');
      var stepTitle = steps[current].getAttribute('data-step-title') || ('Step ' + (current + 1));
      titles.forEach(function(t) { t.textContent = stepTitle; });
    }

    // Validate current step
    function validate() {
      var step = steps[current];
      var fields = step.querySelectorAll('input, select, textarea');
      var valid = true;
      fields.forEach(function(f) {
        f.style.outline = '';
        if (f.hasAttribute('required') || f.closest('[data-required]')) {
          var val = f.value ? f.value.trim() : '';
          if (!val) {
            f.style.outline = '2px solid #ff4f6a';
            valid = false;
          }
        }
      });
      return valid;
    }

    // Go to step
    function goTo(idx) {
      if (idx < 0 || idx >= total) return;
      steps[current].style.display = 'none';
      current = idx;
      steps[current].style.display = '';
      updateUI();
      // Scroll to form top
      form.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }

    // Bind next buttons
    function bindButtons() {
      // Next buttons inside each step
      steps.forEach(function(step, i) {
        var nextBtns = step.querySelectorAll('[data-ff-next], [data-step-next]');
        nextBtns.forEach(function(btn) {
          btn.addEventListener('click', function(e) {
            e.preventDefault();
            if (validate()) {
              if (i + 1 < total) goTo(i + 1);
            }
          });
        });
        var prevBtns = step.querySelectorAll('[data-ff-prev], [data-step-prev]');
        prevBtns.forEach(function(btn) {
          btn.addEventListener('click', function(e) {
            e.preventDefault();
            if (i - 1 >= 0) goTo(i - 1);
          });
        });
      });

      // Global next/prev buttons
      var globalNext = document.querySelectorAll('[data-ff-next-global]');
      globalNext.forEach(function(btn) {
        btn.addEventListener('click', function(e) {
          e.preventDefault();
          if (validate() && current + 1 < total) goTo(current + 1);
        });
      });
      var globalPrev = document.querySelectorAll('[data-ff-prev-global]');
      globalPrev.forEach(function(btn) {
        btn.addEventListener('click', function(e) {
          e.preventDefault();
          if (current - 1 >= 0) goTo(current - 1);
        });
      });
    }

    // Prevent form submit on non-last steps
    form.addEventListener('submit', function(e) {
      if (current < total - 1) {
        e.preventDefault();
        if (validate()) goTo(current + 1);
      }
    });

    bindButtons();
    updateUI();
    console.log('[FormFlow] Initialized form with ' + total + ' steps');
  }

  // Auto-init
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

  // Webflow page transitions support
  if (window.Webflow) {
    window.Webflow.push(init);
  }

  window.FormFlow = { init: init };
})();
